const expected = $env.AGENT_REACH_WEBHOOK_SECRET || '';
const runnerSecret = $env.AGENT_REACH_RUNNER_SECRET || expected;
const headers = $json.headers || {};
const fromWebhook = Object.keys(headers).length > 0;
if (expected && fromWebhook) {
  const auth = headers.authorization || headers.Authorization || '';
  const headerSecret = headers['x-agent-reach-secret'] || headers['X-Agent-Reach-Secret'] || '';
  if (auth !== `Bearer ${expected}` && headerSecret !== expected) throw new Error('Unauthorized Agent Reach webhook call');
}
const scheduleRequest = {
  sources: $env.AGENT_REACH_SOURCES || 'exa,official,rss',
  limitKeywords: Number($env.AGENT_REACH_LIMIT_KEYWORDS || 54),
  exaResults: Number($env.AGENT_REACH_EXA_RESULTS || 3),
  officialResults: Number($env.AGENT_REACH_OFFICIAL_RESULTS || 3),
  rssResults: Number($env.AGENT_REACH_RSS_RESULTS || 8),
};
if (!fromWebhook) {
  const scheduleUrl = `${$env.SUPABASE_URL}/rest/v1/collection_schedules?key=eq.agent_reach&select=enabled,daily_time,timezone`;
  const response = await fetch(scheduleUrl, { headers: { apikey: $env.SUPABASE_SERVICE_ROLE_KEY, Authorization: `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}` } });
  if (!response.ok) throw new Error(`Collection schedule lookup failed: ${response.status}`);
  const rows = await response.json();
  const schedule = rows[0] || { enabled: true, daily_time: '06:30', timezone: 'Asia/Seoul' };
  const parts = new Intl.DateTimeFormat('en-GB', { timeZone: schedule.timezone || 'Asia/Seoul', hour: '2-digit', minute: '2-digit', hourCycle: 'h23' }).formatToParts(new Date());
  const hour = parts.find((part) => part.type === 'hour').value;
  const minute = parts.find((part) => part.type === 'minute').value;
  if (!schedule.enabled || `${hour}:${minute}` !== String(schedule.daily_time || '06:30').slice(0, 5)) return [];
}
const request = fromWebhook && $json.body && typeof $json.body === 'object' ? $json.body : scheduleRequest;
return [{ json: { trigger: fromWebhook ? 'webhook' : 'schedule', runnerUrl: $env.AGENT_REACH_RUNNER_URL || 'http://host.docker.internal:8787/run', runnerSecret, request } }];
